import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.Materializer

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem("webhook-proxy-service")
    implicit val materializer = Materializer()

    val route = post {
      entity(as[Uri]) { userUrl =>
        val request = HttpRequest(uri = userUrl)
        onComplete(Http().singleRequest(request)) { response =>
          complete(response.entity.dataBytes.map(_.utf8String))
        }
      }
    }

    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    bindingFuture.onComplete {
      case Success(binding) =>
        println(s"Webhook Proxy Service started, listening on ${binding.localAddress}")
      case Failure(ex) =>
        Console.err.println("Webhook Proxy Service failed to start!")
    }
  }
}